import { lazy, Suspense, useEffect, useMemo, useState } from 'react'
import { useParams, Link, useNavigate } from 'react-router-dom'
import { getPageBySlug } from '../api/cms'
import { SeoHead } from '../components/SeoHead'
import JsonLd from '../components/JsonLd'
import { useTranslation } from '../i18n/useTranslation'
import { defaultLang, langToOgLocale, langPrefix } from '../i18n/translations'
import { buildHreflangAlternates } from '../utils/seoHreflang'
import { absolutizeCmsHtml } from '../utils/cmsAssetUrl'
import { isCmsPlaceholderContent } from '../utils/cmsPlaceholderContent'
import ResourceCenterPage from './ResourceCenterPage'
import './CmsPage.css'

const SectionPlaceholderPage = lazy(() => import('./SectionPlaceholderPage'))

function plainText(html) {
  if (!html || typeof html !== 'string') return ''
  return html.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim()
}

export default function CmsPage({ fixedSlug }) {
  const { slug: paramSlug } = useParams()
  const slug = fixedSlug || paramSlug
  const lang = defaultLang
  const t = useTranslation(lang)
  const navigate = useNavigate()
  const [data, setData] = useState(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)

  useEffect(() => {
    if (!slug) return undefined
    setLoading(true)
    setError(null)
    setData(null)
    getPageBySlug(slug, lang)
      .then(setData)
      .catch((e) => setError(e.message))
      .finally(() => setLoading(false))
    return undefined
  }, [slug, lang])

  useEffect(() => {
    const redir = data?._seo_redirect
    if (!redir?.locale || !redir?.slug) return
    navigate(`${langPrefix(redir.locale)}/page/${encodeURIComponent(redir.slug)}`, { replace: true })
  }, [data, navigate])

  const alternateLocalesKey = Array.isArray(data?.alternate_locales)
    ? [...data.alternate_locales].sort().join(',')
    : ''
  const hreflangAlternates = useMemo(() => {
    if (!data || data._seo_redirect || error) return null
    const origin = typeof window !== 'undefined' ? window.location.origin : ''
    const alt = buildHreflangAlternates(data.slug || slug, data.alternate_locales, 'page', origin)
    return alt.length ? alt : null
  }, [data, error, slug, alternateLocalesKey])

  const fallbackTitle = String(data?.title || '').trim()
  const fallbackDescription = plainText(data?.content || '').slice(0, 160)
  const showComingSoon = isCmsPlaceholderContent(data?.content || '')

  if (loading) {
    return (
      <article className="cms-page wrap cms-page--skeleton" aria-busy="true">
        <SeoHead title={slug ? String(slug).replace(/-/g, ' ') : 'Page'} robots="noindex" />
        <div className="cms-skeleton-block">
          <div className="cms-skeleton-title" />
          <div className="cms-skeleton-line" />
          <div className="cms-skeleton-line" />
          <div className="cms-skeleton-line cms-skeleton-line--short" />
        </div>
      </article>
    )
  }

  if (data?._seo_redirect) {
    return (
      <div className="cms-page wrap">
        <p className="cms-page-loading">Redirecting…</p>
      </div>
    )
  }

  if (error || !data) {
    if (fixedSlug === 'insights') {
      return (
        <Suspense
          fallback={(
            <article className="cms-page wrap cms-page--skeleton" aria-busy="true">
              <div className="cms-skeleton-block">
                <div className="cms-skeleton-title" />
                <div className="cms-skeleton-line" />
              </div>
            </article>
          )}
        >
          <SectionPlaceholderPage sectionKey="insights" />
        </Suspense>
      )
    }
    return (
      <div className="cms-page wrap">
        <SeoHead title="" />
        <p className="cms-page-error">{error || 'Page not found.'}</p>
        <Link to="/" className="cms-page-back">← Back to home</Link>
      </div>
    )
  }

  const metaDescription = showComingSoon
    ? t('cms.comingSoon')
    : (data.meta_description || fallbackDescription || '').trim()

  if (data.layout === 'resource_center') {
    return <ResourceCenterPage pageData={data} lang={lang} />
  }

  return (
    <article className="cms-page wrap">
      <JsonLd data={data.json_ld} />
      <SeoHead
        title={(data.meta_title || fallbackTitle || '').trim()}
        description={metaDescription}
        keywords={data.meta_keywords || ''}
        canonical={data.canonical_url}
        robots={(data.meta_robots || 'index,follow').trim()}
        ogTitle={(data.og_title || data.meta_title || fallbackTitle || '').trim()}
        ogDescription={(data.og_description || metaDescription || '').trim()}
        ogImage={data.og_image}
        ogLocale={langToOgLocale(lang)}
        hreflangAlternates={hreflangAlternates}
        ogType="website"
      />
      <header className="cms-page-header">
        <h1 className="cms-page-title">{data.title}</h1>
      </header>
      {showComingSoon ? (
        <p className="cms-page-coming-soon">{t('cms.comingSoon')}</p>
      ) : (
        <div
          className="cms-page-content"
          dangerouslySetInnerHTML={{ __html: absolutizeCmsHtml(data.content || '') }}
        />
      )}
      <footer className="cms-page-footer">
        <Link to="/" className="cms-page-back">
          ← Back to home
        </Link>
      </footer>
    </article>
  )
}
