/**
 * True when CMS HTML is empty or still the default seeded / stub copy.
 * Used to show a friendly "Coming soon" instead of thin placeholder HTML.
 */
export function isCmsPlaceholderContent(html) {
  if (html == null || typeof html !== 'string') return true
  const stripped = html.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim()
  if (stripped.length > 220) return false
  if (stripped.length < 24) return true
  if (/content for this page can be edited in the cms/i.test(stripped)) return true
  return false
}
