import { useEffect, useMemo, useState } from 'react'
import { Link } from 'react-router-dom'
import { getBlogs } from '../api/cms'
import { SeoHead } from '../components/SeoHead'
import JsonLd from '../components/JsonLd'
import { useTranslation } from '../i18n/useTranslation'
import { defaultLang, langToOgLocale } from '../i18n/translations'
import { absolutizeCmsHtml } from '../utils/cmsAssetUrl'
import { isCmsPlaceholderContent } from '../utils/cmsPlaceholderContent'
import { buildHreflangAlternates } from '../utils/seoHreflang'
import './BlogListPage.css'
import './ResourceCenterPage.css'

const PAGE_SIZE = 9

function formatDate(iso) {
  if (!iso) return ''
  try {
    return new Date(iso).toLocaleDateString(undefined, { dateStyle: 'long' })
  } catch {
    return iso
  }
}

function plainText(html) {
  if (!html || typeof html !== 'string') return ''
  return html.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim()
}

/**
 * CMS layout "resource_center": hero copy from page content + sidebar + blog card grid.
 */
export default function ResourceCenterPage({ pageData, lang: langProp }) {
  const lang = langProp ?? defaultLang
  const t = useTranslation(lang)
  const [blogs, setBlogs] = useState([])
  const [loading, setLoading] = useState(true)
  const [visible, setVisible] = useState(PAGE_SIZE)
  const [q, setQ] = useState('')

  useEffect(() => {
    setLoading(true)
    getBlogs(lang)
      .then((res) => setBlogs(res.blogs || []))
      .catch(() => setBlogs([]))
      .finally(() => setLoading(false))
  }, [lang])

  const filtered = useMemo(() => {
    const s = q.trim().toLowerCase()
    if (!s) return blogs
    return blogs.filter(
      (b) =>
        (b.title || '').toLowerCase().includes(s) || (b.excerpt || '').toLowerCase().includes(s),
    )
  }, [blogs, q])

  const shown = filtered.slice(0, visible)
  const hasMore = visible < filtered.length

  const showComingSoon = isCmsPlaceholderContent(pageData?.content || '')
  const fallbackDescription = plainText(pageData?.content || '').slice(0, 160)
  const metaDescription = showComingSoon
    ? t('cms.comingSoon')
    : (pageData.meta_description || fallbackDescription || '').trim()

  const alternateLocalesKey = Array.isArray(pageData?.alternate_locales)
    ? [...pageData.alternate_locales].sort().join(',')
    : ''
  const hreflangAlternates = useMemo(() => {
    if (!pageData || pageData._seo_redirect) return null
    const origin = typeof window !== 'undefined' ? window.location.origin : ''
    const alt = buildHreflangAlternates(pageData.slug, pageData.alternate_locales, 'page', origin)
    return alt.length ? alt : null
  }, [pageData, alternateLocalesKey])

  const fallbackTitle = String(pageData?.title || '').trim()

  return (
    <article className="resource-center">
      <JsonLd data={pageData.json_ld} />
      <SeoHead
        title={(pageData.meta_title || fallbackTitle || '').trim()}
        description={metaDescription}
        keywords={pageData.meta_keywords || ''}
        canonical={pageData.canonical_url}
        robots={(pageData.meta_robots || 'index,follow').trim()}
        ogTitle={(pageData.og_title || pageData.meta_title || fallbackTitle || '').trim()}
        ogDescription={(pageData.og_description || metaDescription || '').trim()}
        ogImage={pageData.og_image}
        ogLocale={langToOgLocale(lang)}
        hreflangAlternates={hreflangAlternates}
        ogType="website"
      />
      <section className="resource-center-hero" aria-labelledby="resource-center-heading">
        <div className="resource-center-hero-inner wrap">
          <h1 id="resource-center-heading" className="resource-center-title">
            {fallbackTitle}
          </h1>
          {showComingSoon ? (
            <p className="resource-center-coming-soon">{t('cms.comingSoon')}</p>
          ) : (
            <div
              className="resource-center-hero-body cms-page-content"
              dangerouslySetInnerHTML={{ __html: absolutizeCmsHtml(pageData.content || '') }}
            />
          )}
        </div>
      </section>

      <div className="resource-center-main wrap">
        <aside className="resource-center-sidebar" aria-label={t('insights.sidebarLabel')}>
          <label className="resource-center-label" htmlFor="resource-center-search">
            {t('insights.searchKeywords')}
          </label>
          <div className="resource-center-search-row">
            <input
              id="resource-center-search"
              type="search"
              value={q}
              onChange={(e) => {
                setQ(e.target.value)
                setVisible(PAGE_SIZE)
              }}
              className="resource-center-search"
              placeholder={t('insights.searchPlaceholder')}
              autoComplete="off"
            />
          </div>
          <p className="resource-center-label resource-center-label--spaced">{t('insights.filterByType')}</p>
          <nav className="resource-center-nav">
            <Link to="/blog" className="resource-center-nav-link">
              {t('blog.listTitle')}
            </Link>
            <Link to="/contact" className="resource-center-nav-link">
              {t('corporate.ctaContact')}
            </Link>
          </nav>
        </aside>

        <div className="resource-center-content">
          {loading ? (
            <div className="blog-list-skeleton-grid" aria-hidden="true">
              {[1, 2, 3, 4, 5, 6].map((i) => (
                <div key={i} className="blog-card blog-card--skeleton">
                  <div className="blog-card-image-wrap blog-card-image-wrap--skeleton" />
                  <div className="blog-card-body">
                    <div className="blog-skeleton-line blog-skeleton-line--short" />
                    <div className="blog-skeleton-line blog-skeleton-line--title" />
                    <div className="blog-skeleton-line" />
                  </div>
                </div>
              ))}
            </div>
          ) : shown.length === 0 ? (
            <p className="resource-center-empty">{t('blog.noPosts')}</p>
          ) : (
            <>
              <div className="blog-list-grid resource-center-grid">
                {shown.map((post) => (
                  <Link key={post.id} to={`/blog/${post.slug}`} className="blog-card resource-center-card">
                    <div className="blog-card-image-wrap">
                      {post.og_image || post.image ? (
                        <img
                          src={post.og_image || post.image}
                          alt={post.title ? `Cover image for ${post.title}` : 'Article'}
                          className="blog-card-image"
                          loading="lazy"
                          decoding="async"
                        />
                      ) : (
                        <div className="blog-card-image-placeholder" aria-hidden="true" />
                      )}
                    </div>
                    <div className="blog-card-body">
                      <span className="resource-center-pill">{t('insights.pillLabel')}</span>
                      {post.published_at && (
                        <time className="blog-card-date" dateTime={post.published_at}>
                          {formatDate(post.published_at)}
                        </time>
                      )}
                      <h2 className="blog-card-title">{post.title}</h2>
                      {post.excerpt && <p className="blog-card-excerpt">{post.excerpt}</p>}
                      <span className="resource-center-readmore">
                        {t('blog.readMore')}
                        <span aria-hidden="true"> →</span>
                      </span>
                    </div>
                  </Link>
                ))}
              </div>
              {hasMore ? (
                <div className="resource-center-more-wrap">
                  <button
                    type="button"
                    className="resource-center-more"
                    onClick={() => setVisible((v) => v + PAGE_SIZE)}
                  >
                    {t('insights.showMore')}
                  </button>
                </div>
              ) : null}
            </>
          )}
        </div>
      </div>
    </article>
  )
}
