/**
 * Row layout: up to 3 cards per row; leftover row uses 1 (full) or 2 (half/half) cards.
 * Maps to CSS grid (6 columns): full=span 6, half=span 3, third=span 2.
 */
export function getCorporateCardSpanClass(index, total) {
  if (total <= 0) return 'landing-card--span-third'
  let i = 0
  while (i < total) {
    const rem = total - i
    const rowLen = Math.min(3, rem)
    if (index >= i && index < i + rowLen) {
      if (rowLen === 1) return 'landing-card--span-full'
      if (rowLen === 2) return 'landing-card--span-half'
      return 'landing-card--span-third'
    }
    i += rowLen
  }
  return 'landing-card--span-third'
}
