import { lazy, Suspense } from 'react'
import { Routes, Route, Navigate, Outlet, useLocation } from 'react-router-dom'
import SiteLayout from './components/SiteLayout'
import DynamicSeoHead from './components/DynamicSeoHead'
import HreflangLinks from './components/HreflangLinks'

/* Main marketing routes ship in the first JS payload — faster navigations, no lazy chunk wait. */
import CorporateHomePage from './pages/CorporateHomePage'
import BlogListPage from './pages/BlogListPage'
import CmsPage from './pages/CmsPage'
import CmsBlog from './pages/CmsBlog'
import ContactPage from './pages/ContactPage'
import LegalContentPage from './pages/LegalContentPage'

const ComingSoonPage = lazy(() => import('./pages/ComingSoonPage'))
const SectionPlaceholderPage = lazy(() => import('./pages/SectionPlaceholderPage'))

/** Legacy `/en/...` bookmarks → same path without the `en` prefix. */
function EnPrefixRedirect() {
  const location = useLocation()
  const path = location.pathname.replace(/^\/en/, '') || '/'
  const to = path + location.search
  return <Navigate to={to} replace />
}

function PageFallback() {
  return (
    <div className="route-fallback" style={{ minHeight: '120px' }} aria-busy="true" aria-live="polite">
      <span className="sr-only">Loading</span>
    </div>
  )
}

function SiteLayoutWrapper() {
  return (
    <SiteLayout>
      <Suspense fallback={<PageFallback />}>
        <Outlet />
      </Suspense>
    </SiteLayout>
  )
}

function App() {
  return (
    <>
      <DynamicSeoHead />
      <HreflangLinks />
      <Routes>
        <Route path="/en" element={<Navigate to="/" replace />} />
        <Route path="/en/*" element={<EnPrefixRedirect />} />

        <Route path="/" element={<SiteLayoutWrapper />}>
          <Route index element={<CorporateHomePage />} />
          <Route path="page/:slug" element={<CmsPage />} />
          <Route path="blog/:slug" element={<CmsBlog />} />
          <Route path="blog" element={<BlogListPage />} />
          <Route path="contact" element={<ContactPage />} />
          <Route path="legal/:slug" element={<LegalContentPage />} />
          <Route path="platform/:slug" element={<SectionPlaceholderPage sectionKey="platform" />} />
          <Route path="platform" element={<SectionPlaceholderPage sectionKey="platform" />} />
          <Route path="marketplace" element={<SectionPlaceholderPage sectionKey="marketplace" />} />
          <Route path="consultancy/:slug" element={<SectionPlaceholderPage sectionKey="consultancy" />} />
          <Route path="consultancy" element={<SectionPlaceholderPage sectionKey="consultancy" />} />
          <Route path="solutions/:slug" element={<SectionPlaceholderPage sectionKey="solutions" />} />
          <Route path="solutions" element={<SectionPlaceholderPage sectionKey="solutions" />} />
          <Route path="insights" element={<CmsPage fixedSlug="insights" />} />
          <Route path="about/:slug" element={<SectionPlaceholderPage sectionKey="about" />} />
          <Route path="about" element={<SectionPlaceholderPage sectionKey="about" />} />
          <Route path=":legacyTool" element={<ComingSoonPage />} />
        </Route>

        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </>
  )
}

export default App
