import { useEffect, useState } from 'react'
import { Link } from 'react-router-dom'
import { useTranslation } from '../i18n/useTranslation'
import { getBlogs } from '../api/cms'
import { SeoHead } from '../components/SeoHead'
import { defaultLang } from '../i18n/translations'
import './BlogListPage.css'

function formatDate(iso) {
  if (!iso) return ''
  try {
    return new Date(iso).toLocaleDateString(undefined, { dateStyle: 'long' })
  } catch {
    return iso
  }
}

export default function BlogListPage() {
  const lang = defaultLang
  const t = useTranslation(lang)
  const [blogs, setBlogs] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)

  useEffect(() => {
    document.documentElement.lang = lang
  }, [lang])

  useEffect(() => {
    setLoading(true)
    setError(null)
    getBlogs(lang)
      .then((res) => setBlogs(res.blogs || []))
      .catch((e) => setError(e.message))
      .finally(() => setLoading(false))
  }, [lang])

  if (error) {
    return (
      <div className="blog-list-page wrap">
        <SeoHead title={t('blog.listTitle')} />
        <p className="blog-list-error">{error}</p>
        <Link to="/" className="blog-list-back">← {t('blog.backHome')}</Link>
      </div>
    )
  }

  return (
    <article className="blog-list-page wrap" aria-busy={loading}>
      <SeoHead title={t('blog.listTitle')} description={t('blog.listIntro')} />
      <header className="blog-list-header">
        <h1 className="blog-list-title">{t('blog.listTitle')}</h1>
        <p className="blog-list-intro">{t('blog.listIntro')}</p>
      </header>
      {loading ? (
        <div className="blog-list-skeleton-grid" aria-hidden="true">
          {[1, 2, 3, 4, 5, 6].map((i) => (
            <div key={i} className="blog-card blog-card--skeleton">
              <div className="blog-card-image-wrap blog-card-image-wrap--skeleton" />
              <div className="blog-card-body">
                <div className="blog-skeleton-line blog-skeleton-line--short" />
                <div className="blog-skeleton-line blog-skeleton-line--title" />
                <div className="blog-skeleton-line" />
                <div className="blog-skeleton-line blog-skeleton-line--medium" />
              </div>
            </div>
          ))}
        </div>
      ) : blogs.length === 0 ? (
        <p className="blog-list-empty">{t('blog.noPosts')}</p>
      ) : (
        <div className="blog-list-grid">
          {blogs.map((post) => (
            <Link
              key={post.id}
              to={`/blog/${post.slug}`}
              className="blog-card"
            >
              <div className="blog-card-image-wrap">
                {(post.og_image || post.image) ? (
                  <img
                    src={post.og_image || post.image}
                    alt={post.title ? `Cover image for ${post.title}` : 'Blog post'}
                    className="blog-card-image"
                    loading="lazy"
                    decoding="async"
                  />
                ) : (
                  <div className="blog-card-image-placeholder" aria-hidden="true" />
                )}
              </div>
              <div className="blog-card-body">
                {post.published_at && (
                  <time className="blog-card-date" dateTime={post.published_at}>
                    {formatDate(post.published_at)}
                  </time>
                )}
                <h2 className="blog-card-title">{post.title}</h2>
                {post.excerpt && (
                  <p className="blog-card-excerpt">{post.excerpt}</p>
                )}
                <span className="blog-card-link">{t('blog.readMore')} →</span>
              </div>
            </Link>
          ))}
        </div>
      )}
      <footer className="blog-list-footer">
        <Link to="/" className="blog-list-back">← {t('blog.backHome')}</Link>
      </footer>
    </article>
  )
}
