import { useEffect, useRef } from 'react'

const TURNSTILE_SRC = 'https://challenges.cloudflare.com/turnstile/v0/api.js'

function ensureTurnstile() {
  return new Promise((resolve, reject) => {
    if (typeof window === 'undefined') {
      reject(new Error('Turnstile requires a browser'))
      return
    }
    if (window.turnstile) {
      resolve()
      return
    }
    if (!document.getElementById('cf-turnstile-api-js')) {
      const s = document.createElement('script')
      s.id = 'cf-turnstile-api-js'
      s.src = TURNSTILE_SRC
      s.async = true
      s.defer = true
      s.onload = () => {
        if (window.turnstile) resolve()
        else reject(new Error('Turnstile unavailable'))
      }
      s.onerror = () => reject(new Error('Turnstile script failed'))
      document.head.appendChild(s)
      return
    }
    const t0 = Date.now()
    const poll = setInterval(() => {
      if (window.turnstile) {
        clearInterval(poll)
        resolve()
      } else if (Date.now() - t0 > 15000) {
        clearInterval(poll)
        reject(new Error('Turnstile timeout'))
      }
    }, 50)
  })
}

/**
 * Cloudflare Turnstile — loads api.js once, renders widget, reports token via onTokenChange.
 * Remount the component (e.g. change `key`) to reset the widget after a failed submit.
 * @param {{ siteKey: string, onTokenChange: (token: string) => void }} props
 */
export default function TurnstileWidget({ siteKey, onTokenChange }) {
  const containerRef = useRef(null)
  const widgetIdRef = useRef(null)
  const cbRef = useRef(onTokenChange)
  cbRef.current = onTokenChange

  useEffect(() => {
    if (!siteKey?.trim() || !containerRef.current) return undefined

    let cancelled = false
    ensureTurnstile()
      .then(() => {
        if (cancelled || !containerRef.current || !window.turnstile) return
        containerRef.current.innerHTML = ''
        widgetIdRef.current = window.turnstile.render(containerRef.current, {
          sitekey: siteKey.trim(),
          callback: (token) => cbRef.current(token),
          'expired-callback': () => cbRef.current(''),
          'error-callback': () => cbRef.current(''),
        })
      })
      .catch(() => {
        cbRef.current('')
      })

    return () => {
      cancelled = true
      const id = widgetIdRef.current
      widgetIdRef.current = null
      if (id != null && window.turnstile) {
        try {
          window.turnstile.remove(id)
        } catch {
          /* ignore */
        }
      }
    }
  }, [siteKey])

  if (!siteKey?.trim()) return null

  return <div className="contact-form-turnstile" ref={containerRef} />
}
