import { useEffect, useState } from 'react'
import { useParams, Link } from 'react-router-dom'
import { getLegalPage } from '../api/cms'
import { SeoHead } from '../components/SeoHead'
import { defaultLang } from '../i18n/translations'
import './CmsPage.css'

const VALID_SLUGS = ['terms', 'privacy-policy', 'disclaimer', 'about-us', 'cookie-policy']

export default function LegalContentPage() {
  const { slug } = useParams()
  const lang = defaultLang
  const [data, setData] = useState(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)

  useEffect(() => {
    if (!slug || !VALID_SLUGS.includes(slug)) {
      setError('Page not found.')
      setLoading(false)
      return
    }
    setLoading(true)
    setError(null)
    setData(null)
    getLegalPage(slug, lang)
      .then(setData)
      .catch(() => setError('Page not found.'))
      .finally(() => setLoading(false))
  }, [slug, lang])

  if (loading) {
    return (
      <article className="cms-page wrap cms-page--skeleton" aria-busy="true">
        <div className="cms-skeleton-block">
          <div className="cms-skeleton-title" />
          <div className="cms-skeleton-line" />
          <div className="cms-skeleton-line" />
          <div className="cms-skeleton-line cms-skeleton-line--short" />
        </div>
      </article>
    )
  }

  if (error || !data) {
    return (
      <div className="cms-page wrap">
        <SeoHead title="Page not found" />
        <p className="cms-page-error">{error || 'Page not found.'}</p>
        <Link to="/" className="cms-page-back">← Back to home</Link>
      </div>
    )
  }

  return (
    <article className="cms-page wrap">
      <SeoHead title={data.title} description={data.title} />
      <header className="cms-page-header">
        <h1 className="cms-page-title">{data.title}</h1>
      </header>
      <div
        className="cms-page-content legal-content-body"
        dangerouslySetInnerHTML={{ __html: data.content || '' }}
      />
      <footer className="cms-page-footer">
        <Link to="/" className="cms-page-back">
          ← Back to home
        </Link>
      </footer>
    </article>
  )
}
