import { defaultLang } from '../i18n/translations'
import { ucWords } from './ucWords'
import { getCorporateSection, resolvePlaceholderMeta } from '../config/corporateMenuContent'

const SECTION_KEYS = new Set(['platform', 'marketplace', 'consultancy', 'solutions', 'insights', 'about'])

function slugLabel(slug) {
  return slug ? ucWords(String(slug).replace(/-/g, ' ')) : ''
}

/**
 * @param {string} pathname
 * @param {(key: string) => string} t
 * @returns {{ label: string, to?: string }[] | null}
 */
export function buildApimstecBreadcrumbItems(pathname, t) {
  const path = pathname.replace(/\/+$/, '') || '/'
  if (path === '/') return null

  const home = { label: t('nav.home'), to: '/' }

  if (path === '/blog') {
    return [home, { label: t('footerBlog') }]
  }
  if (path.startsWith('/blog/')) {
    const slug = path.slice('/blog/'.length).split('/')[0]
    return [
      home,
      { label: t('footerBlog'), to: '/blog' },
      { label: slugLabel(slug) || t('footerBlog') },
    ]
  }
  if (path.startsWith('/page/')) {
    const slug = path.slice('/page/'.length).split('/')[0]
    return [home, { label: slugLabel(slug) || t('breadcrumb.page') }]
  }
  if (path === '/contact') {
    return [home, { label: t('nav.contactUs') }]
  }
  if (path.startsWith('/legal/')) {
    const slug = path.slice('/legal/'.length).split('/')[0]
    return [home, { label: t('breadcrumb.legal') }, { label: slugLabel(slug) || t('breadcrumb.legal') }]
  }

  const parts = path.split('/').filter(Boolean)
  const first = parts[0]

  if (first && SECTION_KEYS.has(first)) {
    const slug = parts[1] || null
    const meta = resolvePlaceholderMeta(defaultLang, first, slug)
    const section = getCorporateSection(defaultLang, first)
    if (!section) {
      return [home, { label: meta.title }]
    }
    if (!slug) {
      return [home, { label: meta.title }]
    }
    return [home, { label: section.title, to: `/${section.basePath}` }, { label: meta.title }]
  }

  if (parts.length === 1) {
    const seg = parts[0]
    const reserved = new Set([
      'page',
      'blog',
      'contact',
      'legal',
      'platform',
      'marketplace',
      'consultancy',
      'solutions',
      'insights',
      'about',
    ])
    if (!reserved.has(seg)) {
      return [home, { label: slugLabel(seg) }]
    }
  }

  return null
}
