/**
 * Routes where global CMS home SEO (DynamicSeoHead) applies.
 * English is the default: canonical home is `/` (no `/en` in the URL).
 */
export function isCmsHomeSeoRoute(pathname) {
  if (!pathname || typeof pathname !== 'string') return false
  const p = pathname.replace(/\/+$/, '') || '/'
  return p === '/'
}
